   120→void LLVMTarget::storeToConfigAttrs(MLIRContext *context,
   121→                                    SmallVector<NamedAttribute> &config) const {
   122→  Builder b(context);
   123→  auto addString = [&](StringRef name, StringRef value) {
   124→    config.emplace_back(b.getStringAttr(name), b.getStringAttr(value));
   125→  };
   126→  auto addBool = [&](StringRef name, bool value) {
   127→    config.emplace_back(b.getStringAttr(name), b.getBoolAttr(value));
   128→  };
   129→  auto addInt64 = [&](StringRef name, int64_t value) {
   130→    config.emplace_back(b.getStringAttr(name), b.getI64IntegerAttr(value));
   131→  };
   132→
   133→  addString("target_triple", triple);
   134→  addString("cpu", cpu);
   135→  addString("cpu_features", cpuFeatures);
   136→  if (!dataLayout.empty()) {
   137→    addString("data_layout", dataLayout);
   138→  }
   139→  if (vectorWidthInBytes != DEFAULT_VECTOR_WIDTH_IN_BYTES) {
   140→    addInt64("native_vector_size", vectorWidthInBytes);
   141→  }
   142→  if (linkEmbedded != DEFAULT_LINK_EMBEDDED) {
   143→    addBool("link_embedded", linkEmbedded);
   144→  }
   145→  if (debugSymbols != DEFAULT_DEBUG_SYMBOLS) {
   146→    addBool("debug_symbols", debugSymbols);
   147→  }
   148→  if (linkStatic != DEFAULT_LINK_STATIC) {
   149→    addBool("link_static", linkStatic);
   150→  }
   151→  if (sanitizerKind != DEFAULT_SANITIZER_KIND) {
   152→    switch (sanitizerKind) {
   153→    case SanitizerKind::kNone:
   154→      addString("sanitizer", "none");
   155→      break;
   156→    case SanitizerKind::kAddress:
   157→      addString("sanitizer", "address");
   158→      break;
   159→    case SanitizerKind::kThread:
   160→      addString("sanitizer", "thread");
   161→      break;
   162→    }
   163→  }
   164→  if (!staticLibraryOutput.empty()) {
   165→    addString("static_library_output", staticLibraryOutput);
   166→  }
   167→  if (pipelineTuningOptions.LoopInterleaving != DEFAULT_LOOP_INTERLEAVING)
   168→    addBool("loop_interleaving", pipelineTuningOptions.LoopInterleaving);
   169→  if (pipelineTuningOptions.LoopVectorization != DEFAULT_LOOP_VECTORIZATION)
   170→    addBool("loop_vectorization", pipelineTuningOptions.LoopVectorization);
   171→  if (pipelineTuningOptions.LoopUnrolling != DEFAULT_LOOP_UNROLLING)
   172→    addBool("loop_unrolling", pipelineTuningOptions.LoopUnrolling);
   173→  if (pipelineTuningOptions.SLPVectorization != DEFAULT_SLP_VECTORIZATION)
   174→    addBool("slp_vectorization", pipelineTuningOptions.SLPVectorization);
   175→  if (!llvmTargetOptions.MCOptions.ABIName.empty())
   176→    addString("target_abi", llvmTargetOptions.MCOptions.ABIName);
   177→  if (llvmTargetOptions.FloatABIType != DEFAULT_FLOAT_ABI) {
   178→    switch (llvmTargetOptions.FloatABIType) {
   179→    case llvm::FloatABI::Default:
   180→      addString("float_abi", "default");
   181→      break;
   182→    case llvm::FloatABI::Soft:
   183→      addString("float_abi", "soft");
   184→      break;
   185→    case llvm::FloatABI::Hard:
   186→      addString("float_abi", "hard");
   187→      break;
   188→    }
   189→  }
   190→  if (ukernels.compare(DEFAULT_ENABLE_UKERNELS) != 0)
   191→    addString("ukernels", ukernels);
   192→  if (linkUkernelBitcode != DEFAULT_LINK_UKERNEL_BITCODE)
   193→    addBool("link_ukernel_bitcode", linkUkernelBitcode);
   194→}
