   467→//
   468→// Beware adding command-line flags here: IREE is a cross-compiler and can
   469→// compile for multiple targets in a single invocation. Global flags added here
   470→// apply to all targets with no way to override them from hosting applications
   471→// that may need to programmatically set them per target and that's bad.
   472→//
   473→// Flags *must* be added to the LLVMTarget if they are target-specific and
   474→// LLVMTargetOptions if they are apply to the whole backend.
   475→
   476→void LLVMCPUTargetCLOptions::bindOptions(OptionsBinder &binder) {
   477→  // Initialize LLVM targets prior to the iree-llvmcpu-list-targets CLI opt.
   478→  initializeLLVMTargets();
   479→
   480→  static llvm::cl::OptionCategory category("LLVMCPU HAL Target");
   481→
   482→  // General flags.
   483→  binder.opt<bool>(
   484→      "iree-llvmcpu-list-targets", listTargets, llvm::cl::cat(category),
   485→      llvm::cl::desc("Lists all registered targets that the LLVM backend can "
   486→                     "generate code for."),
   487→      llvm::cl::ValueDisallowed, llvm::cl::callback([&](const bool &) {
   488→        llvm::TargetRegistry::printRegisteredTargetsForVersion(llvm::outs());
   489→        exit(0);
   490→      }));
   491→
   492→  // Target invariant flags.
