   596→LLVMTargetOptions LLVMCPUTargetCLOptions::getTargetOptions() {
   597→  LLVMTargetOptions targetOptions;
   598→  targetOptions.systemLinkerPath = systemLinkerPath;
   599→  targetOptions.embeddedLinkerPath = embeddedLinkerPath;
   600→  targetOptions.wasmLinkerPath = wasmLinkerPath;
   601→  targetOptions.keepLinkerArtifacts = keepLinkerArtifacts;
   602→
   603→  if (targetTriple.empty()) {
   604→    targetTriple = llvm::sys::getProcessTriple();
   605→  }
   606→
   607→  ResolveCPUAndCPUFeaturesStatus status;
   608→  std::optional<LLVMTarget> maybeTarget = LLVMTarget::create(
   609→      targetTriple, targetCPU, targetCPUFeatures, linkEmbedded, status);
   610→  (void)status; // Ignore status here, since this code runs at target backend
   611→                // registration time and we don't know if this backend will
   612→                // actually be used, and these error statuses are non-fatal,
   613→                // mostly warning about fallbacks. If the target backend is
   614→                // actually used, any error here will also trigger in
   615→                // loadFromConfigAttr, where we will generate an IR error.
   616→  if (maybeTarget) {
   617→    targetOptions.target = *maybeTarget;
   618→  } else {
   619→    llvm::errs() << "The target CPU is not properly defined.\n";
   620→  }
   621→  LLVMTarget &target = targetOptions.target;
   622→  target.linkStatic = linkStatic;
   623→  target.staticLibraryOutput = staticLibraryOutputPath;
   624→  target.debugSymbols = debugSymbols;
   625→  target.pipelineTuningOptions.LoopInterleaving = llvmLoopInterleaving;
   626→  target.pipelineTuningOptions.LoopVectorization = llvmLoopVectorization;
   627→  target.pipelineTuningOptions.LoopUnrolling = llvmLoopUnrolling;
   628→  target.pipelineTuningOptions.SLPVectorization = llvmSLPVectorization;
   629→  target.sanitizerKind = sanitizerKind;
   630→  target.llvmTargetOptions.MCOptions.ABIName = targetABI;
   631→  target.llvmTargetOptions.FloatABIType = targetFloatABI;
   632→  target.dataLayout = targetDataLayout;
   633→  target.vectorWidthInBytes = targetVectorWidthInBytes;
   634→  target.ukernels = enableUkernels;
   635→  target.linkUkernelBitcode = linkUKernelBitcode;
   636→
   637→  target.populateDefaultsFromTargetMachine();
   638→  return targetOptions;
   639→}
