    26→
    27→LogicalResult runLLVMIRPasses(const LLVMTarget &target,
    28→                              llvm::TargetMachine *machine,
    29→                              llvm::Module *module) {
    30→  llvm::LoopAnalysisManager loopAnalysisManager;
    31→  llvm::FunctionAnalysisManager functionAnalysisManager;
    32→  llvm::CGSCCAnalysisManager cGSCCAnalysisManager;
    33→  llvm::ModuleAnalysisManager moduleAnalysisManager;
    34→
    35→  llvm::PassInstrumentationCallbacks passInstrumentationCallbacks;
    36→  llvm::StandardInstrumentations standardInstrumentations(
    37→      module->getContext(),
    38→      /*DebugLogging=*/false);
    39→  standardInstrumentations.registerCallbacks(passInstrumentationCallbacks);
    40→
    41→  llvm::PassBuilder passBuilder(machine, target.pipelineTuningOptions, {},
    42→                                &passInstrumentationCallbacks);
    43→  llvm::AAManager aa = passBuilder.buildDefaultAAPipeline();
    44→  functionAnalysisManager.registerPass([&] { return std::move(aa); });
    45→
    46→  passBuilder.registerModuleAnalyses(moduleAnalysisManager);
    47→  passBuilder.registerCGSCCAnalyses(cGSCCAnalysisManager);
    48→  passBuilder.registerFunctionAnalyses(functionAnalysisManager);
    49→  passBuilder.registerLoopAnalyses(loopAnalysisManager);
    50→  passBuilder.crossRegisterProxies(loopAnalysisManager, functionAnalysisManager,
    51→                                   cGSCCAnalysisManager, moduleAnalysisManager);
    52→
    53→  switch (target.sanitizerKind) {
    54→  case SanitizerKind::kNone:
    55→    break;
    56→  case SanitizerKind::kAddress: {
    57→    passBuilder.registerOptimizerLastEPCallback(
    58→        [](llvm::ModulePassManager &modulePassManager,
    59→           llvm::OptimizationLevel Level, llvm::ThinOrFullLTOPhase) {
    60→          llvm::AddressSanitizerOptions opts;
    61→          // Can use Never or Always, just not the default Runtime, which
    62→          // introduces a reference to
    63→          // __asan_option_detect_stack_use_after_return, causing linker
    64→          // errors, and anyway we wouldn't really want bother to with a
    65→          // runtime switch for that.
    66→          opts.UseAfterReturn = llvm::AsanDetectStackUseAfterReturnMode::Always;
    67→          bool moduleUseAfterScope = false;
    68→          bool useOdrIndicator = false;
    69→          modulePassManager.addPass(llvm::AddressSanitizerPass(
    70→              opts, moduleUseAfterScope, useOdrIndicator));
    71→        });
    72→  } break;
    73→  case SanitizerKind::kThread: {
    74→    passBuilder.registerOptimizerLastEPCallback(
    75→        [](llvm::ModulePassManager &modulePassManager,
    76→           llvm::OptimizationLevel Level, llvm::ThinOrFullLTOPhase) {
    77→          modulePassManager.addPass(llvm::ModuleThreadSanitizerPass());
    78→          modulePassManager.addPass(llvm::createModuleToFunctionPassAdaptor(
    79→              llvm::ThreadSanitizerPass()));
    80→        });
    81→  } break;
    82→  }
    83→
    84→  if (target.optimizerOptLevel != llvm::OptimizationLevel::O0 ||
    85→      target.sanitizerKind != SanitizerKind::kNone) {
    86→    llvm::ModulePassManager modulePassManager;
    87→    modulePassManager =
    88→        passBuilder.buildPerModuleDefaultPipeline(target.optimizerOptLevel);
    89→    modulePassManager.run(*module, moduleAnalysisManager);
    90→  }
    91→
    92→  if (llvm::verifyModule(*module))
    93→    return failure();
    94→
    95→  return success();
    96→}
    97→
    98→LogicalResult runEmitObjFilePasses(llvm::TargetMachine *machine,
    99→                                   llvm::Module *module,
   100→                                   llvm::CodeGenFileType fileType,
   101→                                   std::string *objData) {
   102→  llvm::SmallVector<char, 0> stream_buffer;
   103→  {
   104→    llvm::raw_svector_ostream ostream(stream_buffer);
   105→    // TODO(ataei): Use non legacy pass mamanger for this.
   106→    llvm::legacy::PassManager passManager;
   107→    passManager.add(
   108→        new llvm::TargetLibraryInfoWrapperPass(machine->getTargetTriple()));
   109→    if (machine->addPassesToEmitFile(passManager, ostream,
   110→                                     /*DwoOut=*/nullptr, fileType)) {
   111→      return failure();
   112→    }
   113→    passManager.run(*module);
   114→  }
   115→  // TODO(ataei): This is a work around stream truncation when directly write to
   116→  // string.
   117→  *objData = std::string(stream_buffer.begin(), stream_buffer.end());
   118→  return success();
