   167→  IREE::HAL::ExecutableTargetAttr
   168→  getExecutableTarget(MLIRContext *context, const LLVMTarget &target) const {
   169→    // Add some configurations to the `hal.executable.target` attribute.
   170→    Builder b(context);
   171→    SmallVector<NamedAttribute> configItems;
   172→    target.storeToConfigAttrs(context, configItems);
   173→
   174→    // Compute the format used at runtime to select the executable loader.
   175→    std::string format;
   176→    if (target.linkStatic) {
   177→      // Static libraries are just string references when serialized so we don't
   178→      // need to specify the target architecture.
   179→      format += "static";
   180→    } else {
   181→      // Construct the [loader]-[format]-[arch] triple.
   182→      llvm::Triple targetTriple(target.getTriple());
   183→      if (target.getLinkEmbedded()) {
   184→        // Using the IREE embedded ELF format/loader.
   185→        format += "embedded-elf-";
   186→      } else {
   187→        // System-specific shared library format.
   188→        format += "system-";
   189→        switch (targetTriple.getObjectFormat()) {
   190→        case llvm::Triple::ObjectFormatType::COFF:
   191→          format += "dll-";
   192→          break;
   193→        case llvm::Triple::ObjectFormatType::ELF:
   194→          format += "elf-";
   195→          break;
   196→        case llvm::Triple::ObjectFormatType::MachO:
   197→          format += "dylib-";
   198→          break;
   199→        case llvm::Triple::ObjectFormatType::Wasm:
   200→          format += "wasm-";
   201→          break;
   202→        default:
   203→          format += "unknown-";
   204→          break;
   205→        }
   206→      }
   207→      format += getIreeArchNameForTargetTriple(targetTriple);
   208→    }
   209→    return b.getAttr<IREE::HAL::ExecutableTargetAttr>(
   210→        b.getStringAttr("llvm-cpu"), b.getStringAttr(format),
   211→        b.getDictionaryAttr(configItems));
   212→  }
